  ('locality-6f0ba476-moex-00289', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '有關房屋稅之課徵規定，下列敘述何者正確？', '["房屋標準價格由不動產評價委員會每3年重行評定1次", "房屋現值在新臺幣10萬元以下者，不論用途一律免徵房屋稅", "若符合所有權人、配偶或直系親屬在該建物設籍之條件，則適用自用住宅房屋稅稅率1.2%", "房屋同時作住家及非住家用者，按實際使用面積分別課徵，但非住家用者，課稅面積不得低於 全部面積之1/5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00290', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依納稅者權利保護法之規定，下列何者錯誤？', '["納稅者為維持自己及受扶養親屬享有符合人性尊嚴之基本生活所需之費用，不得加以課稅", "稅法或其他法律所規定之租稅優惠，為達成其特定政策目的，得免限定實施年限", "主管機關就稅捐事項所作成之解釋函令及其他行政規則，除涉及公務機密、營業秘密或個人隱 私外，均應公開", "中央主管機關為研擬納稅者保護基本政策之諮詢意見，應設置納稅者權利保護諮詢會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00291', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '有關租稅罰法之規定，下列何者錯誤？', '["行政罰以過失為責任要件", "刑事罰以處罰故意行為為原則", "納稅義務人若違反稅法相關規定，應以裁處時法律予以處罰。但裁處前之法律若有變更，則適 用從新從輕原則予以處罰", "租稅行政罰由各主管稅捐稽徵機關處理，刑事罰則是由稅捐稽徵機關移送法院偵辦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "4d74093260e2", "answer_pdf_sha1": "3cf1c8fa20e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1715", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
